    private List<ShipmentDto>? shipments;
    private string destinationFilter = string.Empty;
    private string statusFilter = string.Empty;
    private string? errorMessage;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(destinationFilter)
                || s.Destination.Contains(destinationFilter, StringComparison.OrdinalIgnoreCase))
            .Where(s => string.IsNullOrEmpty(statusFilter)
                || s.Status == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await RefreshAsync();
    }

    private async Task RefreshAsync()
    {
        errorMessage = null;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatusAsync(int id, string newStatus)
    {
        errorMessage = null;
        try
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
            await RefreshAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to update status: {ex.Message}";
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "In Transit" => "bg-info text-dark",
        "Out for Delivery" => "bg-primary",
        "Delivered" => "bg-success",
        _ => "bg-secondary",
    };
}
