@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2 class="mb-4">Dispatcher Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="destinationFilter" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="In Transit">In Transit</option>
            <option value="Out for Delivery">Out for Delivery</option>
            <option value="Delivered">Delivered</option>
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-secondary" @onclick="RefreshAsync">
            Refresh
        </button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <div class="alert alert-info">No shipments match your filters.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (shipment.Status != "Delivered")
                            {
                                <div class="dropdown">
                                    <button class="btn btn-sm btn-outline-primary dropdown-toggle"
                                            type="button" data-bs-toggle="dropdown">
                                        Update
                                    </button>
                                    <ul class="dropdown-menu">
                                        @foreach (var status in new[] { "Pending", "In Transit", "Out for Delivery", "Delivered" })
                                        {
                                            if (status != shipment.Status)
                                            {
                                                var s = status;
                                                var id = shipment.Id;
                                                <li>
                                                    <button class="dropdown-item" @onclick="() => UpdateStatusAsync(id, s)">
                                                        @s
                                                    </button>
                                                </li>
                                            }
                                        }
                                    </ul>
                                </div>
                            }
                            else
                            {
                                <span class="text-muted">—</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger mt-3">@errorMessage</div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string destinationFilter = string.Empty;
    private string statusFilter = string.Empty;
    private string? errorMessage;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(destinationFilter)
                || s.Destination.Contains(destinationFilter, StringComparison.OrdinalIgnoreCase))
            .Where(s => string.IsNullOrEmpty(statusFilter)
                || s.Status == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await RefreshAsync();
    }

    private async Task RefreshAsync()
    {
        errorMessage = null;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatusAsync(int id, string newStatus)
    {
        errorMessage = null;
        try
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
            await RefreshAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to update status: {ex.Message}";
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "In Transit" => "bg-info text-dark",
        "Out for Delivery" => "bg-primary",
        "Delivered" => "bg-success",
        _ => "bg-secondary",
    };
}

